    /**
     * JavaScript bridge that exposes native Android functionality to web content.
     * All methods validate input and handle errors gracefully.
     */
    public class NativeBridge {

        /**
         * Get device information for analytics/compatibility.
         * Called from JS: NativeBridge.getDeviceInfo()
         */
        @JavascriptInterface
        public String getDeviceInfo() {
            try {
                JSONObject info = new JSONObject();
                info.put("platform", "android");
                info.put("sdkVersion", android.os.Build.VERSION.SDK_INT);
                info.put("model", android.os.Build.MODEL);
                info.put("manufacturer", android.os.Build.MANUFACTURER);
                info.put("appVersion", getAppVersion());
                return info.toString();
            } catch (JSONException e) {
                Log.e(TAG, "Error creating device info", e);
                return createErrorResponse("Failed to get device info");
            }
        }

        /**
         * Request camera access and capture a photo.
         * Called from JS: NativeBridge.openCamera(callbackName)
         */
        @JavascriptInterface
        public void openCamera(String callbackName) {
            if (!isValidCallbackName(callbackName)) {
                Log.w(TAG, "Invalid callback name for openCamera");
                return;
            }

            runOnUiThread(() -> {
                if (hasCameraPermission()) {
                    launchCamera(callbackName);
                } else {
                    requestCameraPermission();
                    sendCallbackToWeb(callbackName, createErrorResponse("Camera permission not granted"));
                }
            });
        }

        /**
         * Request current location.
         * Called from JS: NativeBridge.getCurrentLocation(callbackName)
         */
        @JavascriptInterface
        public void getCurrentLocation(String callbackName) {
            if (!isValidCallbackName(callbackName)) {
                Log.w(TAG, "Invalid callback name for getCurrentLocation");
                return;
            }

            if (!hasLocationPermission()) {
                runOnUiThread(() -> requestLocationPermission());
                sendCallbackToWeb(callbackName, createErrorResponse("Location permission not granted"));
                return;
            }

            try {
                CancellationTokenSource cancellationTokenSource = new CancellationTokenSource();

                if (ActivityCompat.checkSelfPermission(MainActivity.this,
                        Manifest.permission.ACCESS_FINE_LOCATION) != PackageManager.PERMISSION_GRANTED) {
                    sendCallbackToWeb(callbackName, createErrorResponse("Location permission not granted"));
                    return;
                }

                fusedLocationClient.getCurrentLocation(Priority.PRIORITY_HIGH_ACCURACY,
                                cancellationTokenSource.getToken())
                        .addOnSuccessListener(location -> {
                            if (location != null) {
                                try {
                                    JSONObject result = new JSONObject();
                                    result.put("success", true);
                                    result.put("latitude", location.getLatitude());
                                    result.put("longitude", location.getLongitude());
                                    result.put("accuracy", location.getAccuracy());
                                    result.put("timestamp", location.getTime());
                                    sendCallbackToWeb(callbackName, result.toString());
                                } catch (JSONException e) {
                                    sendCallbackToWeb(callbackName, createErrorResponse("Failed to serialize location"));
                                }
                            } else {
                                sendCallbackToWeb(callbackName, createErrorResponse("Location unavailable"));
                            }
                        })
                        .addOnFailureListener(e -> {
                            Log.e(TAG, "Location request failed", e);
                            sendCallbackToWeb(callbackName, createErrorResponse("Location request failed"));
                        });
            } catch (Exception e) {
                Log.e(TAG, "Error getting location", e);
                sendCallbackToWeb(callbackName, createErrorResponse("Error getting location"));
            }
        }

        /**
         * Initiate a payment flow using native payment APIs.
         * Called from JS: NativeBridge.initiatePayment(paymentDataJson, callbackName)
         */
        @JavascriptInterface
        public void initiatePayment(String paymentDataJson, String callbackName) {
            if (!isValidCallbackName(callbackName)) {
                Log.w(TAG, "Invalid callback name for initiatePayment");
                return;
            }

            try {
                JSONObject paymentData = new JSONObject(paymentDataJson);

                // Validate required payment fields
                if (!paymentData.has("amount") || !paymentData.has("currency") || !paymentData.has("orderId")) {
                    sendCallbackToWeb(callbackName, createErrorResponse("Missing required payment fields: amount, currency, orderId"));
                    return;
                }

                double amount = paymentData.getDouble("amount");
                String currency = paymentData.getString("currency");
                String orderId = paymentData.getString("orderId");

                // Validate amount
                if (amount <= 0) {
                    sendCallbackToWeb(callbackName, createErrorResponse("Invalid payment amount"));
                    return;
                }

                // Sanitize orderId
                if (!orderId.matches("^[a-zA-Z0-9\\-_]{1,64}$")) {
                    sendCallbackToWeb(callbackName, createErrorResponse("Invalid order ID format"));
                    return;
                }

                runOnUiThread(() -> processPayment(amount, currency, orderId, callbackName));

            } catch (JSONException e) {
                Log.e(TAG, "Invalid payment data JSON", e);
                sendCallbackToWeb(callbackName, createErrorResponse("Invalid payment data format"));
            }
        }

        /**
         * Show a native toast message.
         * Called from JS: NativeBridge.showToast(message)
         */
        @JavascriptInterface
        public void showToast(String message) {
            if (message == null || message.trim().isEmpty()) return;
            // Limit message length
            String safeMessage = message.length() > 200 ? message.substring(0, 200) : message;
            runOnUiThread(() -> Toast.makeText(MainActivity.this, safeMessage, Toast.LENGTH_SHORT).show());
        }

        /**
         * Share content using native share sheet.
         * Called from JS: NativeBridge.shareContent(title, text, url)
         */
        @JavascriptInterface
        public void shareContent(String title, String text, String url) {
            // Validate URL if provided
            if (url != null && !url.isEmpty() && !url.startsWith("https://")) {
                Log.w(TAG, "Blocked share with non-HTTPS URL");
                return;
            }

            runOnUiThread(() -> {
                Intent shareIntent = new Intent(Intent.ACTION_SEND);
                shareIntent.setType("text/plain");
                if (title != null) shareIntent.putExtra(Intent.EXTRA_SUBJECT, sanitizeInput(title, 200));
                StringBuilder shareText = new StringBuilder();
                if (text != null) shareText.append(sanitizeInput(text, 500));
                if (url != null && !url.isEmpty()) {
                    if (shareText.length() > 0) shareText.append("\n");
                    shareText.append(url);
                }
                shareIntent.putExtra(Intent.EXTRA_TEXT, shareText.toString());
                startActivity(Intent.createChooser(shareIntent, "Share via"));
            });
        }

        /**
         * Store a key-value pair securely (using EncryptedSharedPreferences in production).
         * Called from JS: NativeBridge.storeData(key, value)
         */
        @JavascriptInterface
        public boolean storeData(String key, String value) {
            if (!isValidStorageKey(key)) {
                Log.w(TAG, "Invalid storage key");
                return false;
            }
            if (value != null && value.length() > 10000) {
                Log.w(TAG, "Value too large for storage");
                return false;
            }
            try {
                // In production, use EncryptedSharedPreferences
                getSharedPreferences("hybrid_app_data", MODE_PRIVATE)
                        .edit()
                        .putString(key, value)
                        .apply();
                return true;
            } catch (Exception e) {
                Log.e(TAG, "Error storing data", e);
                return false;
            }
        }

        /**
         * Retrieve a stored value by key.
         * Called from JS: NativeBridge.retrieveData(key)
         */
        @JavascriptInterface
        public String retrieveData(String key) {
            if (!isValidStorageKey(key)) {
                Log.w(TAG, "Invalid storage key");
                return null;
            }
            try {
                return getSharedPreferences("hybrid_app_data", MODE_PRIVATE)
                        .getString(key, null);
            } catch (Exception e) {
                Log.e(TAG, "Error retrieving data", e);
                return null;
            }
        }

        /**
         * Check if a specific permission is granted.
         * Called from JS: NativeBridge.checkPermission(permissionType)
         */
        @JavascriptInterface
        public String checkPermission(String permissionType) {
            try {
                JSONObject result = new JSONObject();
                boolean granted = false;

                if ("camera".equalsIgnoreCase(permissionType)) {
                    granted = hasCameraPermission();
                } else if ("location".equalsIgnoreCase(permissionType)) {
                    granted = hasLocationPermission();
                }

                result.put("permission", permissionType);
                result.put("granted", granted);
                return result.toString();
            } catch (JSONException e) {
                return createErrorResponse("Error checking permission");
            }
        }

        /**
         * Request a specific permission.
         * Called from JS: NativeBridge.requestPermission(permissionType)
         */
        @JavascriptInterface
        public void requestPermission(String permissionType) {
            runOnUiThread(() -> {
                if ("camera".equalsIgnoreCase(permissionType)) {
                    requestCameraPermission();
                } else if ("location".equalsIgnoreCase(permissionType)) {
                    requestLocationPermission();
                }
            });
        }

        // Input validation helpers

        private boolean isValidCallbackName(String callbackName) {
            if (callbackName == null || callbackName.isEmpty()) return false;
            // Only allow alphanumeric, dots, underscores (prevent JS injection)
            return callbackName.matches("^[a-zA-Z_$][a-zA-Z0-9_$.]{0,100}$");
        }

        private boolean isValidStorageKey(String key) {
            if (key == null || key.isEmpty()) return false;
            return key.matches("^[a-zA-Z0-9_\\-.]{1,100}$");
        }

        private String sanitizeInput(String input, int maxLength) {
            if (input == null) return "";
            String sanitized = input.replaceAll("[<>\"']", "");
            if (sanitized.length() > maxLength) {
                sanitized = sanitized.substring(0, maxLength);
            }
            return sanitized;
        }
    }

    // Helper methods

    private void sendCallbackToWeb(String callbackName, String data) {
        if (webView == null || callbackName == null) return;

        // Escape the data for safe JavaScript injection
        String escapedData = data.replace("\\", "\\\\")
                .replace("'", "\\'")
                .replace("\n", "\\n")
                .replace("\r", "\\r");

        String js = "javascript:try{" + callbackName + "('" + escapedData + "')}catch(e){console.error('Bridge callback error:',e)}";

        runOnUiThread(() -> webView.evaluateJavascript(
                "try{" + callbackName + "('" + escapedData + "')}catch(e){console.error('Bridge callback error:',e)}",
                null
        ));
    }

    private void injectBridgeReadyEvent(WebView view) {
        String js = "if(typeof window.onNativeBridgeReady==='function'){window.onNativeBridgeReady()}" +
                "window.dispatchEvent(new CustomEvent('nativeBridgeReady'))";
        view.evaluateJavascript(js, null);
    }

    private String createErrorResponse(String message) {
        try {
            JSONObject error = new JSONObject();
            error.put("success", false);
            error.put("error", message);
            return error.toString();
        } catch (JSONException e) {
            return "{\"success\":false,\"error\":\"Unknown error\"}";
        }
    }

    private String getAppVersion() {
        try {
            return getPackageManager().getPackageInfo(getPackageName(), 0).versionName;
        } catch (PackageManager.NameNotFoundException e) {
            return "unknown";
        }
    }

    // Permission helpers

    private boolean hasCameraPermission() {
        return ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA)
                == PackageManager.PERMISSION_GRANTED;
    }

    private boolean hasLocationPermission() {
        return ContextCompat.checkSelfPermission(this, Manifest.permission.ACCESS_FINE_LOCATION)
                == PackageManager.PERMISSION_GRANTED;
    }

    private void requestCameraPermission() {
        ActivityCompat.requestPermissions(this,
                new String[]{Manifest.permission.CAMERA},
                PERMISSION_REQUEST_CAMERA);
    }

    private void requestLocationPermission() {
        ActivityCompat.requestPermissions(this,
                new String[]{
                        Manifest.permission.ACCESS_FINE_LOCATION,
                        Manifest.permission.ACCESS_COARSE_LOCATION
                },
                PERMISSION_REQUEST_LOCATION);
    }

    @Override
    public void onRequestPermissionsResult(int requestCode, @NonNull String[] permissions,
                                           @NonNull int[] grantResults) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults);

        boolean granted = grantResults.length > 0 && grantResults[0] == PackageManager.PERMISSION_GRANTED;

        switch (requestCode) {
            case PERMISSION_REQUEST_CAMERA:
                if (granted) {
                    Toast.makeText(this, "Camera permission granted", Toast.LENGTH_SHORT).show();
                } else {
                    Toast.makeText(this, "Camera permission denied", Toast.LENGTH_SHORT).show();
                }
                // Notify web about permission change
                notifyPermissionChange("camera", granted);
                break;

            case PERMISSION_REQUEST_LOCATION:
                if (granted) {
                    Toast.makeText(this, "Location permission granted", Toast.LENGTH_SHORT).show();
                } else {
                    Toast.makeText(this, "Location permission denied", Toast.LENGTH_SHORT).show();
                }
                notifyPermissionChange("location", granted);
                break;
        }
    }

    private void notifyPermissionChange(String permission, boolean granted) {
        String js = "if(typeof window.onPermissionChange==='function'){" +
                "window.onPermissionChange('" + permission + "'," + granted + ")}";
        runOnUiThread(() -> webView.evaluateJavascript(js, null));
    }

    // Camera helpers

    private void launchCamera(String callbackName) {
        Intent takePictureIntent = new Intent(MediaStore.ACTION_IMAGE_CAPTURE);
        if (takePictureIntent.resolveActivity(getPackageManager()) != null) {
            File photoFile = null;
            try {
                photoFile = createImageFile();
            } catch (IOException e) {
                Log.e(TAG, "Error creating image file", e);
                sendCallbackToWeb(callbackName, createErrorResponse("Failed to create image file"));
                return;
            }

            if (photoFile != null) {
                Uri photoURI = FileProvider.getUriForFile(this,
                        getPackageName() + ".fileprovider",
                        photoFile);
                takePictureIntent.putExtra(MediaStore.EXTRA_OUTPUT, photoURI);
                cameraLauncher.launch(takePictureIntent);
            }
        } else {
            sendCallbackToWeb(callbackName, createErrorResponse("No camera app available"));
        }
    }

    private File createImageFile() throws IOException {
        String timeStamp = new SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(new Date());
        String imageFileName = "JPEG_" + timeStamp + "_";
        File storageDir = getExternalFilesDir(Environment.DIRECTORY_PICTURES);
        File image = File.createTempFile(imageFileName, ".jpg", storageDir);
        currentPhotoPath = image.getAbsolutePath();
        return image;
    }

